function.body:
-- Logistice
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Result NUMBER:=1; -- 0=failure
    v_count NUMBER:=0; -- 0=failure
    v_Record_ID VARCHAR2(32);
    v_User_ID VARCHAR2(32):='0';
    v_Line_ID VARCHAR2(32):='0';

    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Record RECORD;
    Cur_Lines RECORD;

BEGIN

    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);

    BEGIN --BODY
        -- Get Parameters
        v_ResultStr:='ReadingParameters';
        FOR Cur_Parameter IN (
            SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date
            FROM AD_PInstance i
                LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID
            WHERE i.AD_PInstance_ID = P_Instance_ID
            ORDER BY p.SeqNo
        ) LOOP
            v_Record_ID := Cur_Parameter.Record_ID;
            v_User_ID := Cur_Parameter.AD_User_ID;
            IF (Cur_Parameter.ParameterName = 'lineId') THEN
            	v_Line_ID := Cur_Parameter.P_String;      
            END IF;
        END LOOP; -- Get Parameter

		SELECT accredit_value, withh_rent, withh_iva, commision_value, deposit_reference, settled, iva
			INTO Cur_Record
		FROM sccrt_card_load_line 
			WHERE  sccrt_card_load_line_id = v_Line_ID;

        FOR Cur_Lines IN (
            SELECT type, deposit_amount, ssccr_pos_card_rec_line_id
			FROM ssccr_pos_card_rec_line 
			WHERE ssccr_pos_card_rec_id = v_Record_ID
			ORDER BY type
        ) LOOP
            UPDATE ssccr_pos_card_rec_line
            SET updated = now(),
                updatedby = v_User_ID,
                em_sccrt_referencecode = Cur_Record.deposit_reference,
                em_sccrt_liquidated = Cur_Record.settled,
				deposit_amount = CASE type 
					WHEN 'IVA' THEN Cur_Record.iva
					WHEN 'B' THEN Cur_Record.accredit_value
					WHEN 'C' THEN Cur_Record.commision_value
					WHEN 'VW' THEN Cur_Record.withh_iva
					WHEN 'IW' THEN Cur_Record.withh_rent
					ELSE deposit_amount END
            WHERE ssccr_pos_card_rec_line_id = Cur_Lines.ssccr_pos_card_rec_line_id;
			v_count := 1;
        END LOOP; -- Get Cur_Lines

		IF (v_count > 0) THEN
			UPDATE sccrt_card_load_line 
            SET updated = now(),
                updatedby = v_User_ID
			WHERE  sccrt_card_load_line_id = v_Line_ID;
		END IF;

        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message);
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);

        RETURN;
    END; --BODY

    EXCEPTION WHEN OTHERS THEN
        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE( v_ResultStr) ;
        ROLLBACK;
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr);
END SCCRT_UPDATE_LINES
